using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
    WriteIndented = true
};

// ── 1. Strongly-typed metadata ──────────────────────────────────
// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type handled : {personInfo.Type.Name}");
Console.WriteLine($"Kind         : {personInfo.Kind}");
Console.WriteLine($"Properties   : {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized   : {json}");
Console.WriteLine();

// ── 2. Probe without throwing ───────────────────────────────────
// TryGetTypeInfo tells you whether metadata is resolvable,
// returning false instead of throwing if it isn't.
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
{
    Console.WriteLine($"Person metadata found  : {found!.Type.Name}");
}

// For a type the resolver can't handle we still get false, not an exception.
if (!options.TryGetTypeInfo(typeof(Stream), out _))
{
    Console.WriteLine("Stream metadata absent : (no exception thrown)");
}

